class Solution:
    def asteroidsDestroyed(self, mass, asteroids):
        from itertools import permutations
        for order in permutations(asteroids):
            m = mass
            ok = True
            for a in order:
                if m >= a:
                    m += a
                else:
                    ok = False
                    break
            if ok:
                return True
        return False

